/**
 * Parse header injection rules from configuration.
 * Format: "header_name:header_value;header_name:header_value;..."
 * Example: "X-Custom-Header:custom-value;X-Another:another-value"
 */
Config::HeaderInjectionRules parseRules(const std::string& rules_str) {
  Config::HeaderInjectionRules rules;

  if (rules_str.empty()) {
    return rules;
  }

  size_t pos = 0;
  while (pos < rules_str.length()) {
    // Find the next semicolon (or end of string)
    size_t next_semi = rules_str.find(';', pos);
    if (next_semi == std::string::npos) {
      next_semi = rules_str.length();
    }

    // Extract the rule string
    std::string rule_str = rules_str.substr(pos, next_semi - pos);

    // Find the colon separator
    size_t colon_pos = rule_str.find(':');
    if (colon_pos != std::string::npos) {
      std::string header_name = rule_str.substr(0, colon_pos);
      std::string header_value = rule_str.substr(colon_pos + 1);

      if (!header_name.empty() && !header_value.empty()) {
        rules.emplace_back(Config::HeaderInjectionRule{header_name, header_value});
      }
    }

    pos = next_semi + 1;
  }

  return rules;
}

} // namespace

Http::FilterFactoryCb CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const google::protobuf::StringValue& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  // Parse the configuration string
  // Format: "request_rules:header1:value1;header2:value2|response_rules:header3:value3"
  const std::string& config_str = proto_config.value();

  Config::HeaderInjectionRules request_rules;
  Config::HeaderInjectionRules response_rules;

  // Simple parsing: split by pipe for request vs response
  size_t pipe_pos = config_str.find('|');

  if (pipe_pos == std::string::npos) {
    // No pipe, treat all as request rules
    std::string rules_part = config_str;
    if (rules_part.find("request_rules:") == 0) {
      rules_part = rules_part.substr(14); // Remove "request_rules:"
    }
    request_rules = parseRules(rules_part);
  } else {
    // Split by pipe
    std::string request_part = config_str.substr(0, pipe_pos);
    std::string response_part = config_str.substr(pipe_pos + 1);

    // Remove prefixes if present
    if (request_part.find("request_rules:") == 0) {
      request_part = request_part.substr(14);
    }
    if (response_part.find("response_rules:") == 0) {
      response_part = response_part.substr(15);
    }

    request_rules = parseRules(request_part);
    response_rules = parseRules(response_part);
  }

  auto filter_config = std::make_shared<Config>(request_rules, response_rules);

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

absl::StatusOr<Router::RouteSpecificFilterConfigConstSharedPtr>
CustomHeaderInjectionConfig::createRouteSpecificFilterConfigTyped(
    const google::protobuf::StringValue& config,
    Server::Configuration::ServerFactoryContext&,
    ProtobufMessage::ValidationVisitor&) {
  // Parse route-specific config
  const std::string& config_str = config.value();

  Config::HeaderInjectionRules request_rules;
  Config::HeaderInjectionRules response_rules;

  size_t pipe_pos = config_str.find('|');

  if (pipe_pos == std::string::npos) {
    std::string rules_part = config_str;
    if (rules_part.find("request_rules:") == 0) {
      rules_part = rules_part.substr(14);
    }
    request_rules = parseRules(rules_part);
  } else {
    std::string request_part = config_str.substr(0, pipe_pos);
    std::string response_part = config_str.substr(pipe_pos + 1);

    if (request_part.find("request_rules:") == 0) {
      request_part = request_part.substr(14);
    }
    if (response_part.find("response_rules:") == 0) {
      response_part = response_part.substr(15);
    }

    request_rules = parseRules(request_part);
    response_rules = parseRules(response_part);
  }

  return std::make_shared<const Config>(request_rules, response_rules);
}

